    {
      "term": "Transposition",
      "simpleDefinition": "The process of rearranging a mathematical formula to solve for a different unknown variable.",
      "anchor": "Change the side, change the operation.",
      "misconception": "Thinking you can move a term across the equals sign without changing its operation (e.g., moving a multiplier without turning it into a divisor)."
    },
    {
      "term": "Indices",
      "simpleDefinition": "Powers of 10 used to represent very large or very small electrical units, such as kilo (10³) or milli (10⁻³).",
      "anchor": "10 to the power of...",
      "misconception": "Believing that a negative index like 10⁻³ results in a negative number rather than a small decimal fraction."
    },
    {
      "term": "Pythagoras' Theorem",
      "simpleDefinition": "A formula (a² + b² = c²) used to find the length of a missing side in a right-angled triangle.",
      "anchor": "The square of the hypotenuse equals the sum of the squares of the other two sides.",
      "misconception": "Forgetting to calculate the square root of the final sum to find the actual length of the side."
    },
    {
      "term": "Trigonometry (SOHCAHTOA)",
      "simpleDefinition": "The study of the relationships between the angles and sides of triangles, using Sine, Cosine, and Tangent.",
      "anchor": "SOH CAH TOA",
      "misconception": "Confusing the 'Opposite' and 'Adjacent' sides relative to the specific angle being calculated."
    },
    {
      "term": "Mean",
      "simpleDefinition": "The mathematical average calculated by adding a set of values together and dividing by the total number of values.",
      "anchor": "Total sum divided by the count.",
      "misconception": "Confusing the 'mean' (average) with the 'median' (the middle number in a list) when analyzing test results."
    },
    {
      "term": "Percentage",
      "simpleDefinition": "A way of expressing a number as a fraction of 100, often used in electrical work for efficiency or voltage drop.",
      "anchor": "Part over whole, times 100.",
      "misconception": "Applying a percentage calculation to the wrong base value, such as calculating a 5% drop from the load rather than the supply voltage."
    }
  ],
  "anchorPhrases": [
    "Change the side, change the operation.",
    "SOH CAH TOA",
    "Powers of 10",
    "The balance method",
    "Total sum divided by the count"
  ],
  "misconceptionTargets": [
    "10⁻³ is a negative number.",
    "Moving terms across the equals sign without changing the operation.",
    "Confusing the hypotenuse with the adjacent side.",
    "Confusing the mean with the median.",
    "Forgetting to square root at the end of Pythagoras' Theorem."
  ]
}

